// js/questions-y9.js — Year 9 NSW Science question bank (syllabus-aligned, regenerated)
window.QUESTION_BANK = window.QUESTION_BANK || {};
window.QUESTION_BANK[9] = {
  "energy": [
    { q: "The law of conservation of energy states that in a closed system, energy is:", o: ["created from nothing when fuel burns", "destroyed when a machine stops", "neither created nor destroyed, only transformed or transferred", "always converted to kinetic energy"], a: 2, exp: "The law of conservation of energy states that the total energy in a closed system remains constant — it can change form but cannot be created or destroyed." },
    { q: "A 2 kg ball is dropped from a height of 5 m. Using g = 10 m/s², what is its gravitational potential energy at the start?", o: ["10 J", "50 J", "100 J", "200 J"], a: 2, exp: "GPE = mgh = 2 × 10 × 5 = 100 J." },
    { q: "If the same 2 kg ball reaches the ground with 80 J of kinetic energy, how much energy was converted to thermal energy by air resistance?", o: ["20 J", "80 J", "100 J", "180 J"], a: 0, exp: "Total energy = 100 J; KE at bottom = 80 J; thermal energy lost = 100 − 80 = 20 J." },
    { q: "A kettle uses 150 000 J of electrical energy to heat water. The water gains 135 000 J of thermal energy. What is the efficiency of the kettle?", o: ["10%", "50%", "90%", "100%"], a: 2, exp: "Efficiency = (useful output / total input) × 100 = (135 000 / 150 000) × 100 = 90%." },
    { q: "Which device has the highest typical energy efficiency?", o: ["Incandescent light globe (~5%)", "Petrol car engine (~25%)", "Electric motor in an EV (~90%)", "Solar PV panel (~18%)"], a: 2, exp: "Electric motors in electric vehicles typically operate at 85–95% efficiency, far higher than combustion engines or incandescent globes." },
    { q: "Why is 100% efficiency impossible in any real energy transfer?", o: ["Energy is always created during transfers", "Some energy is always lost as thermal energy to the surroundings", "Kinetic energy cannot be converted back to potential energy", "Efficiency is only a theoretical concept"], a: 1, exp: "In every real energy transfer, some energy is converted to thermal energy that disperses into the surroundings and cannot be fully recovered as useful output." },
    { q: "Which strategy is most effective at reducing friction losses in a machine?", o: ["Adding insulation", "Applying a lubricant such as oil or grease", "Using thicker electrical wires", "Reducing the supply voltage"], a: 1, exp: "Lubricants such as oil or grease reduce friction between moving parts, decreasing the amount of kinetic energy converted to wasted thermal energy." },
    { q: "A solar panel receives 800 J of light energy and produces 144 J of electrical energy. What is its efficiency?", o: ["8%", "12%", "18%", "56%"], a: 2, exp: "Efficiency = (144 / 800) × 100 = 18%." },
    { q: "What is the main energy transformation in a swinging pendulum at its lowest point?", o: ["Kinetic energy to electrical energy", "Gravitational potential energy to thermal energy", "Gravitational potential energy to kinetic energy", "Chemical energy to kinetic energy"], a: 2, exp: "At the lowest point of a pendulum swing, all GPE has converted to KE (ignoring friction)." },
    { q: "Which energy source is classified as non-renewable?", o: ["Solar", "Wind", "Coal", "Hydroelectric"], a: 2, exp: "Coal is a fossil fuel formed over millions of years and cannot be replenished on human timescales, making it non-renewable." },
    { q: "What are the three main fossil fuels?", o: ["Coal, uranium, natural gas", "Coal, petroleum, natural gas", "Wood, petroleum, coal", "Solar, wind, coal"], a: 1, exp: "The three main fossil fuels are coal, petroleum (crude oil and its products), and natural gas (mainly methane)." },
    { q: "Wind turbines use which primary form of energy to generate electricity?", o: ["Chemical potential energy", "Gravitational potential energy", "Kinetic energy of moving air", "Thermal energy from the Sun"], a: 2, exp: "Wind turbines extract kinetic energy from moving air; the rotating blades spin a generator to produce electricity." },
    { q: "In a coal-fired power station, what is the correct order of energy transformations?", o: ["Kinetic → Chemical → Electrical", "Chemical → Thermal → Kinetic → Electrical", "Thermal → Chemical → Kinetic → Electrical", "Electrical → Thermal → Chemical"], a: 1, exp: "Coal (chemical PE) is burned → steam is produced (thermal) → steam spins a turbine (kinetic) → generator produces electricity." },
    { q: "Solar photovoltaic (PV) panels are fundamentally different from other electricity generators because they:", o: ["produce direct current (DC) without any moving parts", "use steam to drive a turbine", "require water to cool the solar cells", "only work at night when temperature drops"], a: 0, exp: "Solar PV cells use the photoelectric effect — photons knock electrons free in silicon — producing DC electricity without turbines or moving parts." },
    { q: "Which device converts the DC electricity from solar panels to AC for household use?", o: ["Transformer", "Inverter", "Rectifier", "Capacitor"], a: 1, exp: "An inverter converts the DC electricity generated by solar PV panels to AC electricity for connection to the grid or home circuits." },
    { q: "Which disadvantage is shared by both solar PV and wind energy?", o: ["High greenhouse gas emissions during operation", "Intermittency — they only generate when sun shines or wind blows", "Very high operating costs", "They require large amounts of water"], a: 1, exp: "Both solar and wind are intermittent energy sources: solar panels don't generate at night and wind turbines stop when winds are calm." },
    { q: "What does LCOE stand for and why is it useful for comparing energy sources?", o: ["Levelised Cost Of Electricity — it accounts for full lifetime costs per unit of energy produced", "Long-term Cost Of Electricity — it measures only running costs", "Lowest Cost Of Energy — it identifies the cheapest fuel", "Lifecycle Carbon Of Energy — it measures emissions"], a: 0, exp: "LCOE (Levelised Cost of Electricity) includes capital, operating, and maintenance costs divided by lifetime energy output, giving a fair basis for comparing different energy technologies." },
    { q: "What is the main function of an ammeter in a circuit?", o: ["Measures voltage across a component", "Measures the resistance of a component", "Measures current flowing through a component", "Stores electrical energy"], a: 2, exp: "An ammeter measures electric current (in amperes) and is connected in series with the component being measured." },
    { q: "How must a voltmeter be connected in a circuit to measure voltage across a component?", o: ["In series with the component", "In parallel with the component", "In series with the battery", "Connected to the switch only"], a: 1, exp: "A voltmeter measures potential difference (voltage) across a component and must be connected in parallel — across the two terminals of that component." },
    { q: "In a series circuit with three lamps, what happens to the other two lamps if one lamp's filament breaks?", o: ["They glow more brightly", "They remain at the same brightness", "They go out completely", "They flicker but stay on"], a: 2, exp: "In a series circuit there is only one path for current; a break anywhere in the circuit stops current flowing everywhere." },
    { q: "In which type of circuit does each component receive the full supply voltage?", o: ["Series circuit", "Parallel circuit", "Open circuit", "Short circuit"], a: 1, exp: "In a parallel circuit, each branch connects directly across the supply, so each component receives the full supply voltage." },
    { q: "A series circuit has a 9 V battery and two resistors: R1 = 3 Ω and R2 = 6 Ω. What is the total resistance?", o: ["2 Ω", "3 Ω", "9 Ω", "18 Ω"], a: 2, exp: "In series, total resistance = R1 + R2 = 3 + 6 = 9 Ω." },
    { q: "Using V = IR, calculate the current in a circuit with 9 V supply and 9 Ω total resistance.", o: ["0.5 A", "1 A", "9 A", "81 A"], a: 1, exp: "I = V/R = 9/9 = 1 A." },
    { q: "State Ohm's law as a word equation.", o: ["Voltage equals current plus resistance", "Voltage equals current multiplied by resistance (V = IR)", "Voltage equals resistance divided by current", "Current equals voltage plus resistance"], a: 1, exp: "Ohm's law states V = IR: voltage equals current multiplied by resistance, provided temperature remains constant." },
    { q: "A resistor has 12 V across it and 2 A flowing through it. What is its resistance?", o: ["2 Ω", "6 Ω", "10 Ω", "24 Ω"], a: 1, exp: "R = V/I = 12/2 = 6 Ω." },
    { q: "On a V–I graph for an ohmic (ideal) resistor, the graph is:", o: ["a curved line bowing upward", "a straight horizontal line", "a straight line through the origin", "a U-shaped curve"], a: 2, exp: "An ohmic conductor has constant resistance, so V = IR produces a straight-line graph through the origin; the gradient equals the resistance." },
    { q: "Why is a filament lamp described as a non-ohmic component?", o: ["Its resistance stays constant at all voltages", "Its resistance decreases as temperature drops", "Its resistance increases as it heats up, so the V–I graph curves", "It obeys V = IR exactly at all voltages"], a: 2, exp: "A filament lamp heats up as more current flows, increasing its resistance, so the V–I graph curves rather than being linear." },
    { q: "A lamp operates at 230 V with a current of 0.5 A. What is its power?", o: ["115 W", "230 W", "460 W", "0.5 W"], a: 0, exp: "P = V × I = 230 × 0.5 = 115 W." },
    { q: "A 1 200 W microwave runs for 5 minutes. How much energy does it transform? (E = P × t)", o: ["6 000 J", "240 000 J", "360 000 J", "6 000 000 J"], a: 2, exp: "E = P × t = 1200 × (5 × 60) = 1200 × 300 = 360 000 J." },
    { q: "What is 1 kilowatt-hour (kWh) equal to in joules?", o: ["1 000 J", "3 600 J", "3 600 000 J", "1 000 000 J"], a: 2, exp: "1 kWh = 1000 W × 3600 s = 3 600 000 J (3.6 MJ)." },
    { q: "A 2 000 W kettle is used for 3 minutes. How many kWh does it consume?", o: ["0.1 kWh", "1 kWh", "6 kWh", "6 000 kWh"], a: 0, exp: "Energy = 2000 W × (3/60) h = 100 Wh = 0.1 kWh." },
    { q: "On Australian household appliances, more stars on the Energy Rating Label means:", o: ["the appliance is more expensive to buy", "the appliance uses more energy per year", "the appliance uses less energy for the same function", "the appliance is older and more reliable"], a: 2, exp: "The Australian Energy Rating Label uses more stars to indicate higher energy efficiency — the appliance does the same job using less electricity." },
    { q: "What two pieces of information does the Australian Energy Rating Label display?", o: ["Star rating and purchase price", "Star rating and estimated annual energy consumption in kWh", "Wattage and voltage only", "Model number and warranty period"], a: 1, exp: "The Energy Rating Label shows a star rating (relative efficiency comparison) and estimated annual electricity consumption in kWh." },
    { q: "A refrigerator uses 450 kWh per year and electricity costs $0.30 per kWh. What is its annual running cost?", o: ["$45", "$135", "$450", "$1 350"], a: 1, exp: "Annual cost = 450 kWh × $0.30/kWh = $135." },
    { q: "Why is saving energy sometimes called the 'first fuel' in the energy transition?", o: ["Saving energy creates new power stations", "Reducing demand is almost always cheaper than generating new supply", "Saving energy produces greenhouse gases", "Energy efficiency has no effect on fossil fuel use"], a: 1, exp: "Reducing energy demand avoids the need to build new generation capacity; it is usually cheaper and faster than any new power source, hence the 'first fuel'." },
    { q: "Which strategy reduces household energy demand through building design rather than new technology?", o: ["Installing solar panels on the roof", "Passive solar design — orienting buildings to use sunlight for heating and shading in summer", "Buying a more efficient refrigerator", "Connecting to the grid"], a: 1, exp: "Passive solar design uses building orientation, window placement, and thermal mass to naturally heat in winter and stay cool in summer without active systems." },
    { q: "Global primary energy consumption roughly doubled between which two years?", o: ["1900 and 1950", "1950 and 1970", "1970 and 2020", "2000 and 2020"], a: 2, exp: "Global primary energy consumption roughly doubled between 1970 and 2020, driven by population growth, industrialisation, and rising living standards." },
    { q: "What does 'energy intensity' declining mean for an economy?", o: ["Total energy use is rising", "The economy uses less energy per dollar of output produced", "Renewable energy is replacing fossil fuels", "The population is decreasing"], a: 1, exp: "Energy intensity measures energy used per dollar of GDP; declining intensity means the economy is becoming more efficient even if total energy use grows." },
    { q: "Hydroelectric power stations generate electricity using:", o: ["Chemical energy from water", "Kinetic energy of flowing water driving a turbine", "Thermal energy from the water", "Nuclear reactions in water"], a: 1, exp: "In a hydroelectric station, gravitational potential energy of stored water converts to kinetic energy as it falls, spinning turbines that drive generators." },
    { q: "Which is a major environmental disadvantage of large hydroelectric dams?", o: ["They emit large amounts of CO2 during operation", "They are highly intermittent", "They flood large land areas and disrupt river ecosystems", "They use uranium as fuel"], a: 2, exp: "Large hydroelectric dams require flooding extensive areas of land, which destroys habitat, displaces communities, and disrupts river ecosystems and fish migrations." },
    { q: "In a parallel circuit, the total current from the battery equals:", o: ["The same current as in any single branch", "Zero, because current is shared", "The sum of currents in all parallel branches", "The smallest branch current"], a: 2, exp: "By conservation of charge, the total current from the battery equals the sum of currents through each parallel branch: I_total = I₁ + I₂ + ..." },
    { q: "A 12 V battery is connected to two parallel branches: one with a 4 Ω resistor and one with a 6 Ω resistor. What current flows through the 4 Ω branch?", o: ["1 A", "2 A", "3 A", "5 A"], a: 2, exp: "I = V/R = 12/4 = 3 A through the 4 Ω branch." },
    { q: "What does 'geothermal energy' use as its primary energy source?", o: ["Heat from the Sun warming the ground surface", "Heat energy from Earth's interior", "Chemical energy from underground rocks", "Radioactive decay of surface soil only"], a: 1, exp: "Geothermal energy harnesses thermal energy from Earth's interior, including heat from its core and from radioactive decay in the crust and mantle." },
    { q: "Why is biomass considered renewable only when managed sustainably?", o: ["Burning biomass releases no CO2", "Biomass is a fossil fuel", "If plants are regrown at the same rate they are harvested, the carbon cycle can balance", "Biomass never runs out because it comes from sunlight"], a: 2, exp: "Biomass is renewable if the plants used are regrown as fast as they are burned, maintaining carbon balance; unsustainable harvesting depletes the resource." },
    { q: "What is the unit of electrical resistance?", o: ["Volt (V)", "Ampere (A)", "Watt (W)", "Ohm (Ω)"], a: 3, exp: "The unit of electrical resistance is the ohm, represented by the Greek letter omega (Ω)." },
    { q: "Which of the following is NOT an essential element of a complete electrical circuit?", o: ["An energy source (battery)", "Conducting wires", "A load (lamp or resistor)", "A transformer"], a: 3, exp: "A complete circuit requires a source, conducting wires, and a load in a closed loop. A transformer is not needed to form a basic complete circuit." },
    { q: "Why does adding more parallel branches increase the total current drawn from a battery?", o: ["Each branch has more resistance", "The battery voltage increases", "More paths reduce total resistance, so more total current flows from the same voltage", "Parallel circuits store more charge"], a: 2, exp: "Each extra parallel branch provides an additional path for current; more paths mean lower total resistance, so the battery supplies more total current." },
    { q: "A 15 Ω resistor is connected to a 9 V supply. Calculate the power dissipated.", o: ["0.6 W", "5.4 W", "135 W", "24 W"], a: 1, exp: "P = V²/R = 81/15 = 5.4 W. Alternatively, I = 9/15 = 0.6 A, then P = VI = 9 × 0.6 = 5.4 W." },
    { q: "Combined heat and power (CHP) improves energy efficiency by:", o: ["Combining wind and solar power into one system", "Capturing waste heat from electricity generation and using it for space or process heating, raising overall efficiency above 80%", "Burning two fuels simultaneously", "Combining nuclear and gas into one plant"], a: 1, exp: "CHP (co-generation) captures thermal energy that would otherwise be wasted from a power plant's exhaust and uses it productively, greatly improving overall efficiency." },
    { q: "Which of the following is a non-renewable energy source?", o: ["Wind", "Tidal", "Natural gas", "Geothermal"], a: 2, exp: "Natural gas (mainly methane) is a fossil fuel formed over millions of years and consumed faster than it can be replenished, making it non-renewable." },
    { q: "Regenerative braking in electric vehicles conserves energy by:", o: ["Burning extra fuel to recharge the battery when slowing", "Converting kinetic energy back to electrical energy stored in the battery during deceleration", "Increasing friction to generate heat energy stored in the battery", "Using gravity on slopes to slow the vehicle"], a: 1, exp: "Regenerative braking converts kinetic energy back into electrical energy (stored in the battery) when the vehicle decelerates, rather than wasting it as friction heat." },
    { q: "An incandescent globe converts about 5% of electrical energy to light. Where does the remaining 95% go?", o: ["It is stored in the glass", "It is converted to sound energy", "It is wasted as thermal energy (heat)", "It is reflected back as electrical energy"], a: 2, exp: "The remaining 95% of electrical energy in an incandescent globe is converted to thermal energy (heat), making it extremely inefficient at producing light." },
    { q: "In a series circuit, if the supply is 12 V and resistor R1 drops 4 V, what voltage does R2 drop?", o: ["4 V", "8 V", "12 V", "16 V"], a: 1, exp: "In series, voltages add to the supply: V₁ + V₂ = 12 V, so V₂ = 12 − 4 = 8 V." },
    { q: "An ammeter reading is identical at all points in a series circuit. This demonstrates which rule?", o: ["Voltage is constant in series", "Current is the same everywhere in a series circuit", "Resistance adds up in series", "Power is shared equally in series"], a: 1, exp: "In a series circuit there is only one path for current, so the same number of charges passes each point per second — current is constant throughout." },
    { q: "Which energy transformation occurs in a hydroelectric turbine?", o: ["Chemical PE → Kinetic", "Gravitational PE → Kinetic → Electrical", "Thermal → Kinetic → Electrical", "Nuclear → Thermal → Electrical"], a: 1, exp: "In a hydroelectric station: water at height has gravitational PE → falling water converts this to kinetic energy → kinetic energy spins the turbine and generator → electrical energy is produced." },
    { q: "Why does a shorter carbon-chain hydrocarbon fraction from crude oil condense near the TOP of the fractionating column?", o: ["Shorter chains are denser and rise higher", "Shorter chains have lower boiling points and condense at the cooler top of the column", "Shorter chains react with longer chains and float upward", "The top of the column is hotter, favouring shorter chains"], a: 1, exp: "The fractionating column is hotter at the base and cooler at the top; shorter-chain hydrocarbons have lower boiling points and therefore condense (turn back to liquid) at the cooler upper sections." },
    { q: "What energy transformation occurs in a battery-powered lamp?", o: ["Electrical energy → Chemical energy → Light", "Chemical PE → Electrical energy → Light and thermal energy", "Light → Electrical energy → Chemical PE", "Kinetic energy → Electrical energy → Light"], a: 1, exp: "A battery converts chemical PE to electrical energy; the lamp converts electrical energy to light (and some waste heat/thermal energy)." }
  ],

  "diseases": [
    { q: "Homeostasis is best defined as:", o: ["the process of fighting infections", "maintaining stable internal conditions within the body", "removing waste products from the blood", "producing hormones for growth"], a: 1, exp: "Homeostasis is the process by which the body maintains stable internal conditions (such as temperature, blood glucose, and pH) within a narrow range." },
    { q: "What is the normal set point for core human body temperature?", o: ["35°C", "37°C", "39°C", "41°C"], a: 1, exp: "Normal core body temperature is approximately 37°C; temperatures below 35°C cause hypothermia and above 40°C can denature enzymes and cause seizures." },
    { q: "Why must blood pH be kept within the narrow range of 7.35–7.45?", o: ["To allow red blood cells to carry oxygen only", "Because even small pH changes disrupt enzyme function and nerve cell firing", "To keep the heart pumping at the right rate", "Because all hormones require this pH to be produced"], a: 1, exp: "Even small deviations in blood pH disrupt enzyme activity and nerve cell function; values outside 6.9–7.8 are life-threatening." },
    { q: "What is a negative feedback loop?", o: ["A loop that amplifies changes away from the set point", "A loop that reverses changes and restores conditions to the set point", "A loop that only operates during disease", "A loop that speeds up a process to completion"], a: 1, exp: "In negative feedback, a change away from the set point triggers a response that opposes and reverses that change, restoring stable conditions." },
    { q: "Blood clotting is an example of which type of feedback?", o: ["Negative feedback", "Positive feedback", "Homeostatic suppression", "Hormonal inhibition"], a: 1, exp: "Blood clotting uses positive feedback — each stage releases chemicals that accelerate the next stage, rapidly driving the clotting process to completion." },
    { q: "Which system uses electrical impulses along neurons to send signals?", o: ["Endocrine system", "Digestive system", "Nervous system", "Lymphatic system"], a: 2, exp: "The nervous system transmits signals as electrical impulses along nerve cells (neurons); it is very fast, acting in milliseconds." },
    { q: "Which system uses chemical messengers (hormones) transported in the blood?", o: ["Nervous system", "Endocrine system", "Immune system", "Respiratory system"], a: 1, exp: "The endocrine system releases hormones from glands into the bloodstream; these chemical messengers travel throughout the body and act on target cells." },
    { q: "Which body system responds FASTER — nervous or endocrine?", o: ["Endocrine is faster (seconds)", "Nervous is faster (milliseconds)", "They act at exactly the same speed", "Speed depends only on the hormone type"], a: 1, exp: "Nervous responses travel as electrical impulses and act in milliseconds; endocrine responses travel via the bloodstream and take seconds to hours." },
    { q: "Which part of the brain is the main control centre for temperature regulation?", o: ["Cerebellum", "Medulla oblongata", "Hypothalamus", "Cerebral cortex"], a: 2, exp: "The hypothalamus detects changes in blood temperature and coordinates responses such as sweating, shivering, vasodilation, and vasoconstriction." },
    { q: "Which hormone does the pancreas release when blood glucose is too high after a meal?", o: ["Glucagon", "Adrenaline", "Insulin", "Thyroxine"], a: 2, exp: "When blood glucose rises after a meal, the pancreas releases insulin, signalling body cells to absorb glucose and the liver to store it as glycogen." },
    { q: "Adrenaline is released by the adrenal glands during:", o: ["deep sleep", "digestion of a large meal", "the fight-or-flight response to danger", "blood glucose regulation"], a: 2, exp: "Adrenaline is a hormone released by the adrenal glands in response to perceived danger; it increases heart rate, breathing rate, and redirects blood to muscles for rapid response." },
    { q: "What is the difference between an infectious and a non-infectious disease?", o: ["Infectious diseases are always fatal; non-infectious are not", "Infectious diseases are caused by pathogens and can spread; non-infectious diseases cannot be transmitted between people", "Infectious diseases only affect children", "Non-infectious diseases are always genetic"], a: 1, exp: "Infectious diseases are caused by pathogens and can pass from one person to another; non-infectious diseases (such as type 2 diabetes) cannot be transmitted." },
    { q: "Which of the following is an infectious disease?", o: ["Type 2 diabetes", "Asthma", "Influenza", "Coronary heart disease"], a: 2, exp: "Influenza is caused by the influenza virus (a pathogen) and spreads between people, making it an infectious disease." },
    { q: "Which of the following is a non-infectious disease?", o: ["Tuberculosis", "Malaria", "Melanoma (skin cancer)", "Chickenpox"], a: 2, exp: "Melanoma is caused by UV damage to skin cells (an environmental risk factor), not a pathogen, so it cannot be passed from person to person." },
    { q: "Which type of pathogen is described as non-living and requires a host cell to reproduce?", o: ["Bacterium", "Fungus", "Protozoan", "Virus"], a: 3, exp: "Viruses are non-cellular agents that can only reproduce by entering a living host cell and using its machinery; outside a host they cannot replicate." },
    { q: "Which disease is caused by a bacterium?", o: ["Influenza", "Malaria", "Tuberculosis", "Tinea (athlete's foot)"], a: 2, exp: "Tuberculosis (TB) is caused by the bacterium Mycobacterium tuberculosis; malaria is protozoan, influenza is viral, and tinea is fungal." },
    { q: "What does 'endemic' mean when describing a disease?", o: ["A disease that spreads to every continent", "A disease constantly present at a low level in a particular population or region", "A sudden large increase in disease cases in a region", "A disease that has been completely eradicated"], a: 1, exp: "An endemic disease is one that is constantly present at relatively low but stable levels in a particular population or geographic region — for example, dengue fever in northern Queensland." },
    { q: "An epidemic is best described as:", o: ["A disease present globally on all continents", "A disease completely new to science", "A sudden, larger-than-expected increase in cases in a particular region", "A disease that affects only animals"], a: 2, exp: "An epidemic occurs when disease cases rise sharply above the normally expected level in a region within a defined time period." },
    { q: "What makes COVID-19 classified as a pandemic rather than an epidemic?", o: ["It was a completely new virus never seen before", "It spread across multiple countries and continents, affecting large numbers worldwide", "It caused more deaths than any other disease in history", "It was only found in one country initially"], a: 1, exp: "A pandemic is an epidemic that has spread across several countries or continents; COVID-19 met this criterion when it rapidly spread globally from early 2020." },
    { q: "What is the difference between disease incidence and disease prevalence?", o: ["Incidence is number of deaths; prevalence is number of cases", "Incidence counts new cases in a time period; prevalence counts all existing cases at a given time", "Incidence measures severity; prevalence measures spread", "They mean exactly the same thing"], a: 1, exp: "Incidence counts new cases arising during a period; prevalence counts all existing cases (new and old) at a specific point in time." },
    { q: "Which of the following is the FIRST line of defence against pathogens?", o: ["Antibodies produced by B-cells", "Phagocytes engulfing pathogens", "The skin, mucus, cilia, and stomach acid", "Memory cells from previous infections"], a: 2, exp: "The first line of defence includes physical and chemical barriers such as skin, mucus, cilia, stomach acid, and tears that prevent pathogens from entering the body." },
    { q: "What is phagocytosis?", o: ["The production of antibodies by B-cells", "White blood cells engulfing and digesting pathogens", "The release of hormones to fight infection", "The process of forming memory cells"], a: 1, exp: "Phagocytosis is when white blood cells called phagocytes (such as macrophages and neutrophils) engulf and digest pathogens — part of the non-specific second line of defence." },
    { q: "What is an antibody?", o: ["A white blood cell that engulfs pathogens", "A Y-shaped protein made by B-cells that binds specifically to one type of antigen", "A chemical released during inflammation", "A type of vaccine protein"], a: 1, exp: "Antibodies are Y-shaped proteins produced by B-cells that bind specifically to antigens on the surface of a particular pathogen, marking it for destruction." },
    { q: "What is a memory cell?", o: ["A nerve cell that stores long-term memories", "A long-lived B- or T-cell that enables a faster immune response on re-exposure to the same pathogen", "A white blood cell that kills all pathogens non-specifically", "A type of platelet involved in clotting"], a: 1, exp: "Memory B- and T-cells persist in the body after infection; on re-exposure to the same pathogen they produce a faster, stronger secondary immune response." },
    { q: "How does a vaccine stimulate immunity without causing disease?", o: ["It contains live, fully active pathogens that infect the body mildly", "It contains weakened, inactivated, or partial pathogen antigens that trigger an immune response without causing illness", "It directly injects pre-made antibodies into the bloodstream", "It destroys existing pathogens in the body chemically"], a: 1, exp: "Vaccines contain harmless forms of pathogen antigens (weakened, killed, or fragments); these trigger B- and T-cell activation and memory cell formation without causing disease." },
    { q: "What is herd immunity?", o: ["Immunity shared between animals and humans", "The point at which vaccinated cattle are protected from disease", "When enough people in a population are immune that the pathogen cannot spread widely, protecting unvaccinated individuals indirectly", "The immunity gained only by surviving a disease"], a: 2, exp: "Herd immunity occurs when a high enough proportion of a population is immune that the pathogen cannot find enough new hosts to spread, indirectly protecting those unable to be vaccinated." },
    { q: "Why are antibiotics ineffective against viral infections such as influenza?", o: ["Antibiotics are too expensive to use against viruses", "Antibiotics target bacterial cell structures (like cell walls) that viruses do not have", "Viruses are too large for antibiotics to penetrate", "Viruses are not classified as pathogens"], a: 1, exp: "Antibiotics work by targeting structures unique to bacteria (such as cell walls and bacterial ribosomes); viruses have none of these, so antibiotics have no effect on them." },
    { q: "Which of the following is a modifiable risk factor for cardiovascular disease?", o: ["Age", "Biological sex", "Smoking", "Family history of heart disease"], a: 2, exp: "Smoking is modifiable — a person can choose to stop; age, sex, and family history are non-modifiable risk factors that cannot be changed." },
    { q: "What is one way an individual can reduce their risk of developing type 2 diabetes?", o: ["Receiving a vaccination", "Taking antibiotics regularly", "Maintaining a healthy weight through regular exercise and a balanced diet", "Avoiding UV exposure"], a: 2, exp: "Type 2 diabetes is strongly linked to obesity and physical inactivity — both modifiable factors; regular exercise and a healthy diet significantly reduce risk." },
    { q: "What is 'quarantine' in the context of disease control?", o: ["Giving antibiotics to everyone in a community", "Separating people exposed to an infectious disease from the rest of the population to prevent potential spread", "Requiring all travellers to be vaccinated before entering a country", "Treating infected people with antiviral medication"], a: 1, exp: "Quarantine separates people who have been exposed to an infectious disease (but may not yet show symptoms) to prevent them from potentially transmitting the pathogen to others." },
    { q: "What is a vector in disease transmission?", o: ["A contaminated surface that pathogens survive on", "A living organism (often an insect) that carries and transmits a pathogen from one host to another", "The portal of entry into the body", "A type of vaccine delivery method"], a: 1, exp: "A vector is a living organism — typically an insect — that transmits a pathogen between hosts; for example, mosquitoes are the vector for malaria." },
    { q: "Which Aboriginal plant, used by Bundjalung Peoples, has been confirmed in modern studies to have antimicrobial properties?", o: ["Gumbi gumbi (Pittosporum angustifolium)", "Melaleuca alternifolia (tea tree)", "Emu bush (Eremophila spp.)", "Eucalyptus tetrodonta (stringybark)"], a: 1, exp: "Bundjalung Peoples crushed Melaleuca alternifolia (tea tree) leaves and applied them to wounds; modern research confirms the essential oil contains terpinen-4-ol with antimicrobial activity." },
    { q: "What are the three lines of defence against pathogens in the human body?", o: ["Antibodies, vaccines, and surgery", "Physical/chemical barriers; non-specific immune response; specific adaptive immune response", "Fever, inflammation, and memory cells only", "Skin, blood, and bone marrow"], a: 1, exp: "The three lines are: 1st line (physical/chemical barriers: skin, mucus, cilia), 2nd line (non-specific: inflammation, phagocytes, fever), 3rd line (specific: B-cells, T-cells, antibodies, memory cells)." },
    { q: "Why does fever help fight infection?", o: ["Fever directly melts pathogen cell membranes", "Higher body temperature slows bacterial growth and speeds up immune cell activity", "Fever increases blood glucose available for white blood cells", "Fever triggers immediate antibody production"], a: 1, exp: "Fever raises body temperature above the optimal growth range for many bacteria and accelerates immune cell reactions, helping the body fight infection more effectively." },
    { q: "What is the role of killer T-cells in the immune response?", o: ["They produce antibodies that bind to antigens", "They destroy body cells that have been infected by a virus", "They form the physical first-line barrier to pathogens", "They produce hormones to coordinate the immune response"], a: 1, exp: "Killer T-cells (cytotoxic T-cells) directly destroy body cells that have been infected by viruses, preventing the virus from replicating and spreading." },
    { q: "Which example best disproves the claim that all diseases can be caught from another person?", o: ["Influenza — caused by a virus", "Malaria — spread by mosquitoes", "Cystic fibrosis — an inherited genetic condition", "Tuberculosis — spread by airborne droplets"], a: 2, exp: "Cystic fibrosis is a genetic disorder caused by inherited faulty genes, not a pathogen; it cannot be transmitted between people, disproving the claim." },
    { q: "Which of the following is NOT a mode of infectious disease transmission?", o: ["Droplets from coughing or sneezing", "Vector-borne transmission (e.g. mosquito bite)", "Contact with a contaminated surface (fomite)", "Inheriting a genetic mutation from a parent"], a: 3, exp: "Inheriting a genetic mutation passes on a non-infectious genetic condition, not a pathogen; the other three are genuine modes of pathogen transmission." },
    { q: "Australian immunisation data for measles shows that as vaccination coverage increased, disease case numbers:", o: ["Increased sharply", "Remained unchanged", "Decreased significantly", "Fluctuated randomly with no pattern"], a: 2, exp: "Historical Australian data clearly shows that as measles vaccination coverage increased (especially after introduction of the 2-dose program), notified cases fell dramatically." },
    { q: "The cochlear implant developed by Professor Graeme Clark works by:", o: ["Transplanting a healthy ear from a donor", "Electronically stimulating the auditory nerve, bypassing damaged cochlear hair cells", "Using gene therapy to regrow inner ear cells", "Amplifying all sounds using a powerful hearing aid"], a: 1, exp: "The cochlear implant uses electrode arrays to directly stimulate the auditory nerve with electrical signals, bypassing non-functioning cochlear hair cells to restore hearing in profoundly deaf people." },
    { q: "A vaccine containing a weakened (attenuated) but living pathogen is called:", o: ["An inactivated vaccine", "A live attenuated vaccine", "An mRNA vaccine", "A subunit vaccine"], a: 1, exp: "A live attenuated vaccine contains living but weakened (attenuated) pathogen that cannot cause serious disease but still triggers a full immune response and memory cell formation." },
    { q: "Why does the secondary immune response (re-exposure to a pathogen) produce antibodies faster than the primary response?", o: ["The body has pre-made antibodies stored from first exposure", "Memory B-cells from the first exposure multiply rapidly and produce specific antibodies", "The pathogen is weaker the second time it is encountered", "T-cells are more numerous after any first exposure"], a: 1, exp: "Memory B-cells formed during the primary response persist in the body and respond very rapidly upon re-exposure, producing a faster and larger antibody response." },
    { q: "Why is overuse of antibiotics a public health concern?", o: ["It causes more side effects in all patients", "It wastes money but has no other significant effects", "It drives the evolution of antibiotic-resistant bacteria that are harder to treat", "It makes vaccines less effective in the population"], a: 2, exp: "Overuse and misuse of antibiotics provides selection pressure for resistant bacteria to proliferate; antibiotic-resistant infections are increasingly difficult and expensive to treat." },
    { q: "Which body system provides the FASTEST response to a sudden painful stimulus?", o: ["Endocrine system", "Digestive system", "Nervous system via a reflex arc", "Immune system"], a: 2, exp: "The nervous system via a reflex arc (through the spinal cord) produces a response in milliseconds — far faster than the endocrine system which acts over seconds to hours." },
    { q: "In Type 1 diabetes, which homeostatic process fails?", o: ["The body overproduces insulin, keeping blood glucose too low", "The immune system destroys insulin-producing beta cells, so blood glucose cannot be regulated", "The kidneys fail to filter glucose from the blood", "The liver stops breaking down glycogen"], a: 1, exp: "In Type 1 diabetes, the immune system mistakenly destroys the insulin-producing beta cells of the pancreas; without insulin, blood glucose rises dangerously after meals." },
    { q: "Mucus and cilia in the airways form part of which line of defence?", o: ["Third line — specific immune response", "Second line — non-specific immune response", "First line — physical and chemical barriers", "No specific line — they are structural features only"], a: 2, exp: "Mucus traps pathogens and particles; cilia sweep this material out of the airways — both are first-line physical barriers that prevent pathogens from entering deeper tissues." },
    { q: "A disease has low incidence but high prevalence. What does this most likely indicate?", o: ["The disease kills patients very quickly", "The disease is extremely rare in the community", "The disease is long-lasting (chronic) once contracted", "The disease has recently been eradicated"], a: 2, exp: "Low incidence means few new cases arise each year, but high prevalence means many existing cases persist — typical of a long-lasting (chronic) condition such as HIV or cardiovascular disease." },
    { q: "The Gardasil vaccine developed in Australia protects against:", o: ["Influenza virus", "Human papillomavirus (HPV), which causes most cervical cancers", "Hepatitis B virus", "Measles virus"], a: 1, exp: "Gardasil, developed by Professor Ian Frazer and Dr Jian Zhou at the University of Queensland, is a subunit vaccine against HPV, the primary cause of cervical cancer." },
    { q: "Some people cannot be vaccinated (e.g. newborns or people on chemotherapy). How are they protected in a highly vaccinated community?", o: ["Their strong immune systems protect them naturally", "They are protected by herd immunity — the pathogen cannot spread widely enough to reach them", "They take antibiotics instead of vaccines", "They are naturally immune to all diseases"], a: 1, exp: "Herd immunity means that when most people in a community are vaccinated, the pathogen rarely circulates, indirectly protecting those who cannot receive vaccines for medical reasons." },
    { q: "Which risk factor for non-infectious disease is NON-modifiable?", o: ["Diet quality", "Physical activity level", "Cigarette smoking", "Family (genetic) history of the disease"], a: 3, exp: "Genetic and family history are non-modifiable — a person cannot change their inherited genes — whereas diet, exercise, and smoking are lifestyle choices that can be altered." },
    { q: "Airborne transmission of disease occurs when:", o: ["Infected droplets fall directly onto mucous membranes", "A mosquito injects a pathogen into the blood", "Tiny particles containing the pathogen remain suspended in air for minutes to hours and are inhaled", "A person touches a contaminated surface then touches their face"], a: 2, exp: "Airborne transmission involves very small aerosol particles that remain suspended in air for extended periods and can be inhaled; this is how tuberculosis and measles spread." },
    { q: "An effector in a homeostatic response is:", o: ["A structure that detects a stimulus", "A chemical messenger circulating in the blood", "A muscle or gland that carries out the body's response", "The brain region that analyses information"], a: 2, exp: "An effector is a muscle or gland that carries out the body's response after receiving signals from the nervous or endocrine system (e.g. sweat glands, blood vessels, muscles)." },
    { q: "A stimulus is best defined as:", o: ["A hormone that triggers an immune response", "A detectable change in the internal or external environment", "A type of white blood cell activated by infection", "A feedback mechanism in the endocrine system"], a: 1, exp: "A stimulus is any detectable change in the environment (internal or external) that an organism can respond to via its nervous or endocrine system." },
    { q: "What is the main advantage of the endocrine system for controlling long-term processes such as growth or puberty?", o: ["Hormones act faster than nerve impulses", "Hormones travel in the blood and produce long-lasting effects throughout the body", "Endocrine responses are more precise in targeting specific cells only", "Hormones can override nerve impulses in emergencies"], a: 1, exp: "The endocrine system uses hormones that circulate in the blood and can produce effects lasting hours to days — ideal for regulating slow, sustained processes like growth, metabolism, and puberty." },
    { q: "How do Torres Strait Islander Peoples' cultural protocols for sea country management function similarly to modern fisheries regulations?", o: ["Both require written scientific reports to justify each harvest", "Both limit overharvesting and protect breeding populations to maintain long-term viability", "Both were developed by government scientists in the 20th century", "Both use satellite tracking of fish populations"], a: 1, exp: "Traditional sea country protocols — which govern when, where, and how much of a species can be harvested — limit overharvesting and protect breeding aggregations, functioning as de facto conservation rules similar in effect to modern fisheries regulations." },
    { q: "Which gland releases thyroxine to raise metabolic rate during long-term cold exposure?", o: ["Adrenal gland", "Pancreas", "Thyroid gland", "Pituitary gland"], a: 2, exp: "The hypothalamus signals the thyroid gland (via the pituitary) to release thyroxine; thyroxine raises the metabolic rate of body cells, generating more heat over the long term as part of the endocrine response to cold." }
  ],

  "materials": [
    { q: "What does it mean to say that Australia's mineral resources are 'finite'?", o: ["They can be replenished within a human lifetime", "They were formed in the last 100 years and are still growing", "They were formed over millions of years and cannot be replaced once extracted and used", "They are only found in very small quantities worldwide"], a: 2, exp: "Mineral resources such as iron ore and bauxite were formed over millions to billions of years through geological processes; once extracted and used, they cannot be replenished on human timescales." },
    { q: "In which Australian state is the majority of iron ore produced?", o: ["Queensland", "New South Wales", "Western Australia", "South Australia"], a: 2, exp: "Australia's main iron ore deposits are in the Pilbara region of Western Australia, making WA the dominant iron ore-producing state." },
    { q: "What is the primary use of lithium extracted in Australia?", o: ["Making steel beams for construction", "Making electrical wiring", "Manufacturing batteries for electric vehicles and electronics", "Producing aluminium for aircraft"], a: 2, exp: "Lithium is processed into battery-grade compounds used in lithium-ion batteries for electric vehicles, laptops, and smartphones — a rapidly growing demand." },
    { q: "What is valency?", o: ["The number of protons in an atom's nucleus", "The number of electrons in the outer shell only", "The number of electrons an atom must gain, lose, or share to achieve a stable electron configuration", "The atomic mass of an element in grams"], a: 2, exp: "Valency is the number of electrons an atom needs to gain, lose, or share in order to achieve a stable (noble gas) electron configuration." },
    { q: "What is the octet rule?", o: ["Atoms must always have 8 protons to be stable", "Atoms achieve stability by having 8 electrons in their outermost shell", "All compounds contain exactly 8 atoms per molecule", "Noble gases have 8 neutrons"], a: 1, exp: "The octet rule states that atoms tend to gain, lose, or share electrons until they have 8 electrons in their outer shell, matching the stable configuration of a noble gas (helium follows a duet rule with 2)." },
    { q: "Why are noble gases (Group 18) unreactive?", o: ["They have no protons in their nucleus", "Their outer electron shells are completely full, giving them no tendency to gain or lose electrons", "They are too small to react with other atoms", "They only exist at very high temperatures"], a: 1, exp: "Noble gases already have a full outer electron shell (helium: 2; all others: 8 electrons), so they have no tendency to gain, lose, or share electrons in chemical reactions." },
    { q: "Which type of bond forms between a metal and a non-metal through complete electron transfer?", o: ["Covalent bond", "Metallic bond", "Ionic bond", "Hydrogen bond"], a: 2, exp: "An ionic bond forms when a metal atom transfers one or more electrons to a non-metal atom, creating oppositely charged ions that attract each other by electrostatic force." },
    { q: "Which type of bond forms when two non-metal atoms share electrons?", o: ["Ionic bond", "Metallic bond", "Covalent bond", "Nuclear bond"], a: 2, exp: "Covalent bonds form between non-metal atoms through the sharing of electron pairs; each atom counts the shared electrons as part of its own outer shell." },
    { q: "In metallic bonding, what allows metals to conduct electricity?", o: ["Ions vibrating in the lattice carry charge", "Delocalised electrons that move freely throughout the metal structure carry charge", "Shared electron pairs between adjacent metal atoms", "Ions that transfer electrons to neighbouring ions"], a: 1, exp: "Metallic bonding consists of positive metal ions in a sea of delocalised electrons that move freely; these mobile electrons carry electric current." },
    { q: "What is a cation?", o: ["A negatively charged ion formed by gaining electrons", "A positively charged ion formed by losing electrons", "An atom with an equal number of protons and electrons", "A type of covalent bond partner"], a: 1, exp: "A cation is a positively charged ion; it forms when an atom loses one or more electrons, leaving more protons than electrons and creating a net positive charge." },
    { q: "What is an anion?", o: ["A positively charged ion formed by losing electrons", "A negatively charged ion formed by gaining electrons", "An uncharged atom in a covalent molecule", "A particle found in the atomic nucleus"], a: 1, exp: "An anion is a negatively charged ion formed when a non-metal atom gains electrons, giving it more electrons than protons." },
    { q: "A sodium atom (11 protons, 11 electrons) loses 1 electron. How many electrons does the Na⁺ ion have?", o: ["12", "11", "10", "9"], a: 2, exp: "Na loses 1 electron: 11 − 1 = 10 electrons. The Na⁺ ion has 11 protons and 10 electrons, matching the electron configuration of neon." },
    { q: "A chlorine atom has 17 protons. When it gains 1 electron to form Cl⁻, how many electrons does it have?", o: ["16", "17", "18", "19"], a: 2, exp: "Cl gains 1 electron: 17 + 1 = 18 electrons. The Cl⁻ ion has 17 protons and 18 electrons, matching the configuration of argon." },
    { q: "Which set correctly lists all seven diatomic elements?", o: ["H₂, N₂, O₂, F₂, Cl₂, Br₂, I₂", "H₂, He₂, O₂, N₂, F₂, Cl₂, Ne₂", "H₂, C₂, N₂, O₂, F₂, Cl₂, Br₂", "Li₂, Na₂, K₂, F₂, Cl₂, Br₂, I₂"], a: 0, exp: "The seven diatomic elements are H₂, N₂, O₂, F₂, Cl₂, Br₂, and I₂ — remembered by the mnemonic 'Have No Fear Of Ice Cold Beer'." },
    { q: "Why must oxygen be written as O₂ in chemical equations rather than as O?", o: ["Single oxygen atoms do not exist under any conditions", "Oxygen naturally exists as paired atoms bonded covalently; O does not represent its actual form", "O₂ has twice the mass, making equations balance more easily", "IUPAC rules require all elements to be written with subscript 2"], a: 1, exp: "Oxygen is a diatomic element — it naturally exists as O₂ molecules at standard conditions; writing O would be chemically incorrect and would unbalance equations." },
    { q: "Using the cross-over rule, what is the formula for the ionic compound formed between Ca²⁺ and Cl⁻?", o: ["CaCl", "Ca₂Cl", "CaCl₂", "Ca₂Cl₂"], a: 2, exp: "Cross-over rule: the charge of Ca²⁺ (2) becomes the subscript of Cl, giving CaCl₂ — one Ca²⁺ (+2) balanced by two Cl⁻ (2×−1 = −2), net charge zero." },
    { q: "What is the correct formula for aluminium oxide (Al³⁺ and O²⁻)?", o: ["AlO", "Al₂O", "AlO₂", "Al₂O₃"], a: 3, exp: "Cross-over rule: Al₂O₃. Two Al³⁺ ions (2×+3 = +6) and three O²⁻ ions (3×−2 = −6) give net charge zero: Al₂O₃." },
    { q: "What is the formula of water and what type of bonding holds it together?", o: ["HO — ionic", "H₂O — covalent", "H₂O — metallic", "H₂O₂ — covalent"], a: 1, exp: "Water is H₂O; oxygen (valency 2) forms two covalent bonds with two hydrogen atoms (each valency 1), sharing electron pairs." },
    { q: "What is methane's molecular formula and which compound family does it belong to?", o: ["CH₂ — alkene", "CH₃ — alcohol", "CH₄ — alkane", "C₂H₆ — alkane"], a: 2, exp: "Methane (CH₄) is the first member of the alkane family — hydrocarbons with only single C–C bonds, following the general formula CₙH(2n+2)." },
    { q: "What distinguishes organic compounds from inorganic compounds?", o: ["Organic compounds contain only carbon and oxygen", "Organic compounds contain carbon–hydrogen bonds; inorganic compounds generally do not", "Organic compounds are only found in living organisms today", "Inorganic compounds always contain at least one metal"], a: 1, exp: "The key practical distinction is that organic compounds contain C–H bonds; inorganic compounds such as NaCl, CO₂, and H₂O lack C–H bonds." },
    { q: "Why is CO₂ classified as inorganic even though it contains carbon?", o: ["It doesn't contain hydrogen (lacks C–H bonds)", "It is made of only two different elements", "It is produced by volcanic activity", "It is a colourless gas"], a: 0, exp: "CO₂ lacks carbon–hydrogen bonds (it has only C=O bonds), which is the key criterion separating inorganic carbon-containing compounds from organic ones." },
    { q: "Crude oil is separated into useful fractions by which industrial process?", o: ["Filtration", "Electrolysis", "Fractional distillation", "Chromatography"], a: 2, exp: "Fractional distillation separates crude oil into fractions based on different boiling points; shorter-chain hydrocarbons condense at the cooler top, longer chains at the hotter base." },
    { q: "Which crude oil fraction has the shortest carbon chain and the lowest boiling point?", o: ["Bitumen (>C70)", "Diesel (C14–C20)", "Kerosene (C10–C16)", "Refinery gas / LPG (C1–C4)"], a: 3, exp: "Refinery gas (LPG, C1–C4) has the shortest carbon chains and lowest boiling points (<40°C), condensing at the very top of the fractionating column." },
    { q: "What is the general formula for alkanes?", o: ["CₙH₂ₙ", "CₙH₂ₙ₊₂", "CₙH₂ₙ₋₂", "CₙHₙ"], a: 1, exp: "Alkanes follow the general formula CₙH(2n+2): all carbon-carbon bonds are single bonds, and the number of hydrogen atoms is always 2n+2." },
    { q: "What is the molecular formula for octane?", o: ["C₆H₁₄", "C₇H₁₆", "C₈H₁₈", "C₈H₁₆"], a: 2, exp: "Octane has 8 carbons; using CₙH(2n+2): C₈H(16+2) = C₈H₁₈." },
    { q: "Using IUPAC nomenclature, what is the name of the alkane C₃H₈?", o: ["Methane", "Ethane", "Propane", "Butane"], a: 2, exp: "C₃H₈ has 3 carbon atoms; the IUPAC prefix for 3 carbons is 'prop-' and the alkane suffix is '-ane', giving propane." },
    { q: "What are the products of the COMPLETE combustion of a hydrocarbon?", o: ["Carbon monoxide and water", "Carbon dioxide and water", "Carbon dioxide and hydrogen gas", "Carbon monoxide and hydrogen gas"], a: 1, exp: "In complete combustion (plentiful oxygen), all carbon is fully oxidised to CO₂ and all hydrogen is oxidised to H₂O." },
    { q: "What is the most dangerous product of incomplete combustion?", o: ["Carbon dioxide (CO₂)", "Water vapour (H₂O)", "Carbon monoxide (CO)", "Methane (CH₄)"], a: 2, exp: "Carbon monoxide (CO) is a colourless, odourless, highly toxic gas produced in incomplete combustion; it binds to haemoglobin in blood, preventing oxygen transport." },
    { q: "A Bunsen burner's yellow (safety) flame indicates:", o: ["Complete combustion with plenty of oxygen", "Incomplete combustion with limited oxygen supply", "The highest possible combustion temperature", "The fuel is burning at 100% efficiency"], a: 1, exp: "The yellow (safety) flame results from incomplete combustion when the air hole is closed; the blue roaring flame with the air hole open indicates complete combustion." },
    { q: "What is the difference between a monomer and a polymer?", o: ["A monomer is larger than a polymer", "A monomer is a small repeating unit; a polymer is a long chain made of many monomers joined together", "A polymer is always synthetic; a monomer is always natural", "They are the same substance in different physical states"], a: 1, exp: "Monomers are small molecules (such as ethene) that join together in long chains through polymerisation to form polymers (such as polyethylene)." },
    { q: "What raw material is used to make most synthetic polymers such as polyethylene and polypropylene?", o: ["Wood pulp", "Sugarcane", "Crude oil / petroleum", "Coal tar"], a: 2, exp: "Most synthetic polymers are made from monomers derived from crude oil; fractional distillation and cracking of petroleum produces small reactive molecules like ethene and propene." },
    { q: "What is the key difference between a thermoplastic and a thermosetting plastic?", o: ["Thermoplastics are always transparent; thermosets are opaque", "Thermoplastics soften on heating and can be remoulded; thermosets form permanent cross-links and cannot be re-melted", "Thermosets are made from oil; thermoplastics from plant material", "They are identical in properties but differ in colour"], a: 1, exp: "Thermoplastics (e.g. polyethylene) soften when heated due to weak intermolecular forces; thermosets (e.g. Bakelite) form permanent covalent cross-links when cured and cannot be remelted." },
    { q: "What are microplastics?", o: ["Any plastic that has been recycled", "Plastic particles smaller than 5 mm", "Biodegradable plant-based plastics", "Nanomaterials used in electronics manufacture"], a: 1, exp: "Microplastics are plastic particles less than 5 mm in diameter; they originate as manufactured small particles (primary) or from the breakdown of larger plastic items (secondary)." },
    { q: "What is bioaccumulation in the context of microplastics?", o: ["Microplastics being manufactured from biological materials", "Build-up of microplastics in an organism's tissues faster than they can be eliminated", "The process of breaking down microplastics using bacteria", "Microplastics dissolving slowly in ocean water"], a: 1, exp: "Bioaccumulation occurs when a substance (microplastics and the pollutants they carry) builds up in an organism's tissues over time faster than the organism can excrete it." },
    { q: "What is biomagnification?", o: ["Magnifying microplastics under a microscope", "The increasing concentration of a persistent pollutant at each successive trophic level (step) in a food chain", "The growth of bacteria on plastic surfaces in the ocean", "The decomposition of large plastics into smaller fragments"], a: 1, exp: "Biomagnification is the progressive increase in concentration of persistent pollutants at each trophic level as predators consume many prey organisms, each containing accumulated pollutant." },
    { q: "What is a life cycle assessment (LCA)?", o: ["An assessment of how long a product lasts before it breaks", "An evaluation of total environmental impact of a product from raw material extraction through to final disposal", "A test of a material's physical properties only", "A rating system for biodegradability"], a: 1, exp: "An LCA evaluates environmental impacts at every stage of a product's life — raw materials, manufacturing, use, and end-of-life — across multiple impact categories including carbon footprint, water use, and energy." },
    { q: "Which properties are characteristic of ionic compounds?", o: ["Low melting point and poor solubility in water", "Soft and waxy at room temperature", "High melting point, brittle, and conducts electricity when dissolved in water", "Flexible and conducts electricity as a solid"], a: 2, exp: "Ionic compounds have high melting points (strong electrostatic attraction between ions), are brittle (lattice shatters when layers shift), and conduct electricity when dissolved in water (free ions carry charge)." },
    { q: "Why can metals be beaten into sheets (they are malleable) without shattering?", o: ["Metal atoms share electrons covalently, making them rigid", "Layers of metal ions slide over each other while delocalised electrons maintain the bonding — no fracture occurs", "Metal compounds are all ionic and dissolve easily", "Metals have very low melting points compared to ionic compounds"], a: 1, exp: "In metallic bonding, layers of metal ions can slide past each other while the sea of delocalised electrons adjusts, preventing fracture — this is why metals are malleable and ductile." },
    { q: "Aboriginal Peoples used ochre primarily for:", o: ["Making sharp cutting tools from the mineral", "Body decoration, rock art, and ceremonial purposes — it is an iron oxide pigment", "Waterproofing containers and boats", "Filtering water and treating skin infections"], a: 1, exp: "Ochre (iron oxide minerals in red, yellow, and white shades) was ground to powder and mixed with water, fat, or resin for body decoration, rock art, and ceremony — with evidence of use extending at least 50 000 years in Australia." },
    { q: "What property makes silcrete and chert suitable materials for Aboriginal stone cutting tools?", o: ["They are soft and easily shaped with bare hands", "They are fine-grained and hard, fracturing to produce very sharp edges when knapped", "They contain iron, which gives them strength", "They are found only in coastal regions and are very common"], a: 1, exp: "Hard, fine-grained rocks like silcrete and chert fracture predictably with conchoidal (shell-like) fractures when struck (knapped), producing very sharp-edged tools suitable for cutting and scraping." },
    { q: "What is the IUPAC prefix indicating an organic compound has 6 carbon atoms?", o: ["Pent-", "Hex-", "Hept-", "Oct-"], a: 1, exp: "The IUPAC prefix for 6 carbons is 'hex-' (from the Greek for six); combined with '-ane' for a saturated hydrocarbon it gives 'hexane'." },
    { q: "The alkane with 5 carbon atoms is pentane. What is its molecular formula?", o: ["C₅H₁₀", "C₅H₁₁", "C₅H₁₂", "C₅H₁₄"], a: 2, exp: "Using CₙH(2n+2): C₅H(10+2) = C₅H₁₂ (pentane)." },
    { q: "Which is an advantage of using recycled aluminium rather than producing new aluminium from bauxite?", o: ["Recycled aluminium has higher purity", "Recycling aluminium uses far less energy than electrolytic smelting of bauxite ore", "Bauxite is a renewable resource that grows back", "Recycled aluminium is significantly stronger than new aluminium"], a: 1, exp: "Recycling aluminium requires only about 5% of the energy needed to produce aluminium from bauxite via the Bayer process and electrolytic smelting — a massive energy saving." },
    { q: "What is the Bayer process used for in aluminium production?", o: ["Refining copper from copper ore", "Separating crude oil into useful fractions", "Refining bauxite to produce alumina (Al₂O₃), the precursor to aluminium metal", "Producing steel from iron ore"], a: 2, exp: "The Bayer process dissolves bauxite in hot sodium hydroxide to extract alumina (Al₂O₃), which is then electrolytically smelted to produce aluminium metal." },
    { q: "What is 'acid mine drainage' and why is it an environmental concern?", o: ["Underground acid used to dissolve ore that is safely reused", "Acidic water produced when sulfide minerals in mine waste react with air and water, which can leach heavy metals into waterways", "Acid rain falling specifically on mine sites", "Drain water from mines treated with acid to remove unwanted minerals"], a: 1, exp: "Acid mine drainage forms when sulfide minerals (e.g. pyrite) in exposed waste rock react with air and water to produce sulfuric acid, which leaches heavy metals into nearby waterways." },
    { q: "What is polylactic acid (PLA) and what makes it different from conventional plastics?", o: ["A petroleum-derived plastic with extra flexibility", "A bio-based polymer made from plant sugars (e.g. corn starch), potentially compostable under industrial conditions", "A type of rubber made from latex trees", "A high-density form of polyethylene used in pipes"], a: 1, exp: "PLA is made from lactic acid derived from fermenting plant sugars; unlike petroleum-based plastics, it is bio-based and can biodegrade under industrial composting conditions." },
    { q: "Which of the following is a naturally occurring polymer?", o: ["Polyethylene", "Polypropylene", "Polystyrene", "Cellulose"], a: 3, exp: "Cellulose is a natural polymer found in plant cell walls, composed of glucose monomers linked by covalent bonds; it is not derived from petroleum." },
    { q: "How does the boiling point of heptane (C₇H₁₆, bp ≈ 98°C) compare with pentane (C₅H₁₂, bp ≈ 36°C)?", o: ["Lower — longer chains are lighter", "Higher — longer chains have stronger intermolecular forces", "The same — all liquid alkanes boil at the same temperature", "Lower — branching lowers boiling point significantly"], a: 1, exp: "Boiling point increases with carbon chain length in alkanes because larger molecules have stronger dispersion (intermolecular) forces; heptane boils much higher than pentane." },
    { q: "What does 'organic' mean in chemistry?", o: ["A compound grown without pesticides or synthetic chemicals", "A compound that contains carbon–hydrogen bonds", "Any compound that contains oxygen", "Any naturally occurring mineral compound"], a: 1, exp: "In chemistry, 'organic' refers to compounds containing carbon–hydrogen bonds; this definition does not relate to farming or food production methods." },
    { q: "Why does diamond have an extremely high melting point even though it is a non-metal?", o: ["Ionic bonds — strong attraction between ions throughout the lattice", "Covalent network bonding — every carbon atom is covalently bonded to four others in a giant 3D lattice requiring enormous energy to break", "Metallic bonds — delocalised electrons hold the structure together", "Hydrogen bonds — very numerous throughout the diamond lattice"], a: 1, exp: "Diamond is a covalent network solid; every carbon atom is bonded by strong covalent bonds to four others in a giant 3D lattice — an enormous amount of energy is needed to break all these bonds, giving a very high melting point." },
    { q: "What is the formula for calcium nitrate, given Ca²⁺ and NO₃⁻?", o: ["CaNO₃", "Ca₂NO₃", "Ca(NO₃)₂", "Ca₂(NO₃)₃"], a: 2, exp: "Ca²⁺ has charge +2 and NO₃⁻ has charge −1; two nitrate ions are needed to balance one calcium ion: Ca(NO₃)₂. Parentheses are used because more than one polyatomic ion is needed." },
    { q: "Which type of combustion produces a blue flame and the maximum energy output?", o: ["Incomplete combustion with limited oxygen", "Complete combustion with a plentiful oxygen supply", "Any combustion reaction regardless of oxygen supply", "Combustion of longer-chain alkanes only"], a: 1, exp: "Complete combustion — with a plentiful oxygen supply — produces only CO₂ and H₂O, releases maximum energy, and gives a blue flame (e.g. the roaring blue flame of a Bunsen burner)." },
    { q: "Which formula correctly represents magnesium chloride (Mg²⁺ and Cl⁻)?", o: ["MgCl", "Mg₂Cl", "MgCl₂", "Mg₂Cl₂"], a: 2, exp: "Using the cross-over rule: Mg²⁺ (charge 2) gives subscript 2 on Cl, and Cl⁻ (charge 1) gives subscript 1 on Mg → MgCl₂. One Mg²⁺ (+2) is balanced by two Cl⁻ (2×−1 = −2)." },
    { q: "What is the IUPAC name and molecular formula of the alkane with 7 carbon atoms?", o: ["Hexane, C₆H₁₄", "Heptane, C₇H₁₆", "Octane, C₈H₁₈", "Pentane, C₅H₁₂"], a: 1, exp: "Seven-carbon alkane: prefix 'hept-' + suffix '-ane' = heptane. Using CₙH(2n+2): C₇H(14+2) = C₇H₁₆." },
    { q: "Which property of covalent molecular substances (like sugar or wax) explains their relatively low melting points?", o: ["Strong covalent bonds within each molecule are easily broken by heat", "Weak intermolecular forces between separate molecules require little energy to overcome", "They contain delocalised electrons that lower the melting point", "They are ionic and dissolve easily when heated"], a: 1, exp: "Covalent molecular substances have strong bonds within each molecule but only weak intermolecular (between-molecule) forces; relatively little energy is needed to overcome these weak forces, giving low melting and boiling points." }
  ],

  "sustainability": [
    { q: "According to the Brundtland Report (1987), sustainable development means:", o: ["Using as many resources as possible while they last", "Meeting the needs of the present without compromising the ability of future generations to meet their own needs", "Protecting the environment by stopping all development", "Ensuring economic growth at all costs"], a: 1, exp: "The Brundtland definition states that sustainable development meets present needs without limiting future generations' ability to meet theirs — balancing present and future interests." },
    { q: "Name the three pillars (dimensions) of sustainability.", o: ["Environmental, Economic, and Social", "Physical, Chemical, and Biological", "Local, National, and Global", "Air, Water, and Soil"], a: 0, exp: "The three pillars of sustainability are environmental (ecosystem health), economic (resource efficiency and viability), and social (equitable access for communities now and in the future)." },
    { q: "What is the precautionary principle?", o: ["Acting only once absolute scientific certainty is established", "Taking protective measures against potential environmental harm even if science is not fully established", "Using only renewable resources as a permanent precaution", "Banning all new technologies until tested for 100 years"], a: 1, exp: "The precautionary principle states that when an action risks harm to the environment or health, protective action should be taken even without complete scientific certainty." },
    { q: "What is intergenerational equity?", o: ["Sharing resources equally between all nations today", "Ensuring the current generation does not deplete resources or degrade systems needed by future generations", "All people of one generation receiving the same education", "Reducing economic inequality within a single generation"], a: 1, exp: "Intergenerational equity means the current generation has a responsibility not to over-exploit natural resources or environmental systems, preserving them for future generations." },
    { q: "What is the main difference between weather and climate?", o: ["Weather is measured globally; climate is local", "Weather describes short-term atmospheric conditions; climate describes long-term patterns over at least 30 years", "Climate changes every day; weather is stable over decades", "They mean the same thing but apply to different geographic regions"], a: 1, exp: "Weather refers to day-to-day atmospheric conditions at a specific place; climate is the long-term (30+ years) statistical pattern of weather for a region." },
    { q: "What is the World Meteorological Organization's standard climate normal period?", o: ["10 years", "20 years", "30 years", "100 years"], a: 2, exp: "The WMO defines the standard climate normal period as 30 years (currently 1991–2020) — long enough to average out year-to-year variability and reveal genuine trends." },
    { q: "Which natural greenhouse gas is the largest contributor to the natural greenhouse effect by volume?", o: ["Carbon dioxide (CO₂)", "Water vapour (H₂O)", "Methane (CH₄)", "Nitrous oxide (N₂O)"], a: 1, exp: "Water vapour is the most abundant greenhouse gas in Earth's atmosphere and the largest contributor to the natural greenhouse effect by volume, though it is not the driver of current human-caused warming." },
    { q: "Without the natural greenhouse effect, Earth's average surface temperature would be approximately:", o: ["+15°C (the current temperature)", "0°C", "−18°C", "−60°C"], a: 2, exp: "Without the natural greenhouse effect trapping outgoing infrared radiation, Earth's average surface temperature would be approximately −18°C rather than the current +15°C — a difference of 33°C." },
    { q: "How does the greenhouse effect warm Earth's surface?", o: ["Greenhouse gases block all incoming solar radiation", "The ozone layer traps heat near the surface like a lid", "Greenhouse gases absorb outgoing infrared radiation and re-emit it in all directions, including back toward Earth's surface", "Plants absorb infrared radiation and warm the surrounding air"], a: 2, exp: "Greenhouse gases absorb the infrared (heat) radiation emitted by Earth's warm surface and re-emit it in all directions; energy directed back downward warms the surface further." },
    { q: "What has happened to atmospheric CO₂ since the Industrial Revolution?", o: ["It decreased from 420 ppm to 280 ppm as trees absorbed it", "It stayed steady at about 300 ppm", "It increased from about 280 ppm pre-industrial to over 420 ppm today", "It decreased then returned to pre-industrial levels"], a: 2, exp: "Atmospheric CO₂ rose from approximately 280 ppm before industrialisation (~1750) to over 420 ppm by 2023 — an increase of about 50% driven primarily by fossil fuel combustion and deforestation." },
    { q: "What is the enhanced (anthropogenic) greenhouse effect?", o: ["The natural greenhouse effect that occurs without any human activity", "The intensification of the greenhouse effect caused by human activities increasing greenhouse gas concentrations beyond natural levels", "The effect of greenhouse gases specifically on plant growth and photosynthesis", "Greenhouse gases blocking all incoming solar radiation reaching Earth"], a: 1, exp: "The enhanced greenhouse effect is the strengthening of the natural greenhouse effect because human activities — mainly burning fossil fuels — have raised greenhouse gas concentrations far beyond natural levels." },
    { q: "What is ocean acidification and what causes it?", o: ["Oceans becoming salty due to increased evaporation", "Oceans becoming more acidic as CO₂ dissolves in seawater forming carbonic acid, lowering ocean pH", "Industrial chemicals being deliberately discharged into the ocean", "Natural volcanic activity on the ocean floor releasing acid"], a: 1, exp: "When CO₂ dissolves in seawater it forms carbonic acid, lowering pH. Since 1750, ocean pH has dropped from about 8.2 to 8.1 — a 26% increase in acidity on the pH scale." },
    { q: "Which characteristic best describes the current rate of human-driven climate change?", o: ["It is slower than most natural climate shifts in Earth's past", "It is occurring in one region only", "It is occurring faster than most natural climate shifts and is global in scale", "It is only causing cooling in polar regions"], a: 2, exp: "Current climate change is occurring at an unprecedented rate compared to natural glacial–interglacial transitions, and the warming pattern is global, affecting all ocean basins and continents." },
    { q: "What is 'polar amplification'?", o: ["Polar regions cooling faster than other regions on Earth", "Solar radiation becoming concentrated at the poles", "Polar regions warming two to four times faster than the global average", "Ice sheets amplifying cold temperatures in polar regions"], a: 2, exp: "Polar amplification describes polar regions warming two to four times faster than the global average, partly because melting sea ice reduces reflectivity (albedo), causing further warming." },
    { q: "Approximately how much has global average sea level risen since 1900?", o: ["2 cm", "5 cm", "20 cm", "50 cm"], a: 2, exp: "Global sea level has risen approximately 20 cm since 1900, due to thermal expansion of warming ocean water and the melting of glaciers and ice sheets." },
    { q: "What are the two main causes of global sea level rise due to climate change?", o: ["Increased rainfall and reduced evaporation from oceans", "Thermal expansion of ocean water as it warms, and melting of land-based ice sheets and glaciers", "Rivers carrying more sediment into the oceans and raising the seabed", "Earthquakes on the ocean floor lifting the seabed"], a: 1, exp: "Sea levels rise due to two main mechanisms: (1) thermal expansion — warm water occupies more volume; (2) melting of land ice (glaciers, Greenland, Antarctica) adding water to the ocean." },
    { q: "What is coral bleaching?", o: ["Corals being painted white by scientific researchers", "Corals expelling their symbiotic algae (zooxanthellae) when water temperature rises too high, losing colour and nutrition", "Pollution turning coral white", "Coral shells dissolving due to acidic water"], a: 1, exp: "Coral bleaching occurs when elevated sea temperatures cause corals to expel their zooxanthellae (photosynthetic algae); without these algae corals turn white and can die if high temperatures persist." },
    { q: "What does the 'wet gets wetter, dry gets drier' principle describe about climate change?", o: ["Tropical regions always receive more rainfall than deserts in all seasons", "Climate change is intensifying rainfall in already-wet regions and reducing it in already-dry subtropical regions", "Rainfall will increase everywhere due to increased evaporation", "Glaciers will melt only in regions that receive high rainfall"], a: 1, exp: "As climate change increases atmospheric water vapour, tropical and high-latitude regions generally receive more intense rainfall, while mid-latitude dry zones (including southern Australia) are drying further." },
    { q: "How do satellite radar altimeters measure sea level from space?", o: ["They photograph ocean waves and calculate average height", "They emit radar pulses toward the ocean and precisely measure the return time to calculate the height of the sea surface", "They measure ocean density using infrared sensors", "Weather balloons attached to satellites measure sea level directly"], a: 1, exp: "Radar altimeter satellites (such as Jason-3 and Sentinel-6) emit radar pulses at the ocean surface and measure the return time; the distance to the surface gives sea level height, accurate to about 1 cm." },
    { q: "What is environmental pollution?", o: ["Any change to the natural environment caused by any living organism", "Introduction of substances into the environment at concentrations that cause harm to living organisms, ecosystems, or human health", "Natural disasters such as volcanic eruptions that change landscapes", "Any chemical compound found in soil or water"], a: 1, exp: "Environmental pollution is the introduction of substances or energy into the natural environment at levels that cause harmful effects on organisms, ecosystems, or human health." },
    { q: "What is eutrophication and what causes it?", o: ["The drying up of wetlands due to prolonged drought", "Excess nitrogen and phosphorus from agricultural fertiliser runoff causing algal blooms, oxygen depletion, and fish kills", "Oil spills covering the ocean surface and blocking light", "Acid rain progressively lowering the pH of lakes and rivers"], a: 1, exp: "Eutrophication occurs when excess nutrients (mainly N and P from agricultural runoff) enter waterways, causing rapid algal growth; when algae die and decompose, bacteria consume oxygen, suffocating fish." },
    { q: "What does the waste hierarchy prioritise, from most to least preferred?", o: ["Recycle → Reuse → Reduce → Dispose", "Dispose → Recover → Recycle → Reuse → Reduce", "Reduce → Reuse → Recycle → Recover → Dispose", "Recycle → Reduce → Reuse → Dispose"], a: 2, exp: "The waste hierarchy places Reduce (use less in the first place) as highest priority, then Reuse (extend product life), then Recycle (recover materials), then energy Recovery, with Disposal (landfill) as last resort." },
    { q: "What is the circular economy model?", o: ["An economy based solely on circular (renewable) energy sources", "An economic model that keeps materials in use as long as possible through design for durability, repairability, and recyclability", "The cycle of money flowing through banks and businesses", "An economy that grows in cycles, alternating between expansion and contraction"], a: 1, exp: "The circular economy contrasts with the linear 'take-make-dispose' model; it aims to keep materials and products in use as long as possible by designing for reuse, repair, and recycling." },
    { q: "What is cultural burning (fire-stick farming) practised by Aboriginal Peoples?", o: ["Burning crops after harvest to fertilise the soil for the next growing season", "Carefully timed, low-intensity burns to manage landscapes, reduce fuel loads, promote food plants, and maintain biodiversity", "Burning forests to clear land for farming", "A ceremony involving fire that has no ecological management purpose"], a: 1, exp: "Cultural burning involves low-intensity, strategically timed burns guided by detailed knowledge of seasonal patterns; it clears undergrowth, promotes food plants, creates habitat mosaics, and reduces catastrophic wildfire risk." },
    { q: "What is acid rain and what causes it?", o: ["Rain that is naturally slightly acidic due to dissolved CO₂", "Rain made highly acidic by SO₂ and NOₓ (from fossil fuel combustion) reacting with atmospheric water vapour", "Rain contaminated by agricultural pesticides drifting from fields", "Any rainfall with a pH below 7.0"], a: 1, exp: "Acid rain forms when sulfur dioxide (SO₂) and nitrogen oxides (NOₓ) from fossil fuel combustion react with water vapour in the atmosphere to form sulfuric and nitric acids, lowering rainfall pH significantly." },
    { q: "Why does climate data from multiple independent organisations strengthen scientific confidence?", o: ["Multiple studies are always wrong individually but right collectively", "Independent organisations using different methods reaching the same conclusion strengthens confidence that the result is real", "More data always means the result is automatically correct", "Government organisations are always more reliable than university researchers"], a: 1, exp: "When multiple independent research groups using different measurement methods and data sources reach the same conclusion, it greatly increases confidence in that finding — a key principle of scientific evidence." },
    { q: "What is a phenological shift caused by climate change?", o: ["A change in the pH of an ocean body", "A shift in the timing of seasonal biological events such as flowering, migration, or breeding", "The movement of species to permanently new geographic areas", "Changes in ocean salinity caused by increased evaporation"], a: 1, exp: "Phenological shifts are changes in the timing of seasonal biological events — for example, plants flowering earlier, birds migrating sooner, or insects emerging at different times — driven by changing temperature patterns." },
    { q: "What is the key limitation of solar PV and wind for electricity grids?", o: ["They emit greenhouse gases during operation", "They are too expensive compared to modern coal power", "They are intermittent — they only generate when sunshine or wind is available", "They require nuclear fuel as a backup energy source"], a: 2, exp: "Intermittency is the main challenge for solar and wind energy; solar doesn't generate at night or under heavy cloud, and wind turbines stop when winds are calm or too strong, requiring storage or backup power." },
    { q: "What is carbon capture and storage (CCS)?", o: ["Planting trees to absorb CO₂ from the atmosphere", "Capturing CO₂ emissions from industrial sources and storing them underground to prevent atmospheric release", "Reducing CO₂ emissions by switching to less fossil fuel", "Converting CO₂ into useful fuels using solar energy directly"], a: 1, exp: "CCS involves capturing CO₂ at the source (e.g. a power plant), compressing it, and injecting it into geological formations underground to prevent it from entering the atmosphere." },
    { q: "Why is reforestation a useful strategy to reduce atmospheric CO₂?", o: ["Trees convert CO₂ into oxygen and immediately release the carbon", "Growing trees absorb CO₂ through photosynthesis and store carbon in wood and soil", "Forests produce other greenhouse gases that neutralise CO₂", "Trees reflect solar radiation, reducing the amount of heat reaching Earth"], a: 1, exp: "Trees absorb CO₂ through photosynthesis and store the carbon in biomass and soil; large-scale reforestation can sequester significant amounts of CO₂ from the atmosphere over time." },
    { q: "What does it mean to say atmospheric CO₂ is measured in 'parts per million' (ppm)?", o: ["Parts of CO₂ per million litres of air at sea level", "The number of CO₂ molecules per million total air molecules", "The percentage of CO₂ in the atmosphere multiplied by one million", "The mass of CO₂ in grams per million kilograms of soil"], a: 1, exp: "Parts per million (ppm) means the number of molecules of a given gas per million total molecules of air; current CO₂ at 420 ppm means 420 out of every million air molecules are CO₂." },
    { q: "What was the approximate atmospheric CO₂ concentration before the Industrial Revolution?", o: ["180 ppm", "280 ppm", "380 ppm", "420 ppm"], a: 1, exp: "Ice core records show CO₂ was approximately 280 ppm before the Industrial Revolution (~1750); it has since risen to over 420 ppm — an increase of about 50%." },
    { q: "What is permafrost and why is its thawing a climate change concern?", o: ["Permanently frozen ocean ice in the Arctic Ocean", "Ground frozen for at least two consecutive years; thawing releases stored CO₂ and methane, amplifying warming", "A type of ice sheet found only in Antarctica", "Rock that contains embedded fossils only found in polar regions"], a: 1, exp: "Permafrost is ground that remains at or below 0°C for at least two years; it contains vast organic carbon stores that, when thawed, decompose and release CO₂ and methane — a positive feedback amplifying warming." },
    { q: "Which advantage does reforestation have over carbon capture and storage (CCS)?", o: ["Reforestation can store CO₂ faster than any CCS technology", "Reforestation is proven, relatively low-cost, and provides co-benefits such as biodiversity habitat, water retention, and soil health", "Reforestation always has zero negative environmental side effects", "Reforestation has been demonstrated at larger scale than CCS globally"], a: 1, exp: "Reforestation is a proven, relatively low-cost method with additional environmental co-benefits; CCS is expensive and not yet proven at the scale needed." },
    { q: "How has large-scale fossil fuel combustion since ~1750 driven the rise in atmospheric CO₂?", o: ["Factories produce CO₂ directly from chemical processes unrelated to combustion", "Industrial activity increases electricity demand but not CO₂", "Large-scale burning of fossil fuels releases CO₂ stored for millions of years at rates far exceeding the capacity of natural sinks to absorb it", "Industrialisation replaced forests with factories that absorb CO₂"], a: 2, exp: "Since the Industrial Revolution, burning coal, oil, and gas has released CO₂ stored in fossil fuels over millions of years; natural sinks (oceans, forests) cannot absorb it fast enough, so atmospheric CO₂ accumulates." },
    { q: "In the waste hierarchy, which step has the greatest environmental benefit?", o: ["Recycle — because it recovers materials from waste", "All three steps (reduce, reuse, recycle) have equal environmental benefit", "Reduce — because using less resource in the first place avoids all downstream impacts", "Reuse — because it extends product lifespan"], a: 2, exp: "Reduce is most environmentally beneficial — not using a resource at all avoids all environmental impacts; reuse avoids manufacturing impacts; recycling still requires energy and processing." },
    { q: "What is Indigenous Ecological Knowledge (IEK)?", o: ["Western scientific knowledge applied to study indigenous ecosystems", "Detailed knowledge of seasonal cycles, ecological relationships, and sustainable resource management developed by Aboriginal and Torres Strait Islander Peoples over generations", "Scientific data collected from remote indigenous lands by government researchers", "Environmental regulations developed by Indigenous communities for outsiders"], a: 1, exp: "IEK (Traditional Ecological Knowledge, TEK) is the deep, place-based ecological knowledge developed by Indigenous peoples through millennia of observation, embedded in cultural practices, protocols, and language." },
    { q: "How do satellites measure sea surface temperature?", o: ["Radar altimeters measure the distance to the ocean surface", "Infrared radiometer sensors on polar-orbiting satellites measure heat emitted from the ocean surface", "Satellites lower thermometers on long cables into the water", "Ships collect surface water samples and transmit temperature data to satellites"], a: 1, exp: "Satellites use infrared (thermal) sensors that measure the intensity of infrared radiation emitted by the ocean surface, which corresponds to temperature, producing daily global sea surface temperature maps." },
    { q: "What is the main source of particulate matter (PM2.5) air pollution?", o: ["Evaporation from lakes and rivers", "Combustion processes including vehicle exhaust, coal burning, and bushfire smoke", "Photosynthesis releasing fine particles from plant leaves", "Agricultural irrigation spray drifting in wind"], a: 1, exp: "Fine particulate matter (PM2.5) is produced mainly by combustion — vehicle exhaust, coal and wood burning, and wildfire smoke; these tiny particles penetrate deep into lungs causing cardiovascular and respiratory disease." },
    { q: "A student says: 'It was very cold last winter, so global warming cannot be real.' What is the scientific error?", o: ["The student should check data from more than one country", "Weather in one location over one season cannot refute a long-term global climate trend based on decades of data", "Winter temperatures have no connection to climate change", "The student is correct — local cold winters disprove global warming"], a: 1, exp: "Climate refers to long-term global patterns; one cold season in one location is natural weather variability, not evidence against a decades-long global warming trend confirmed by millions of data points worldwide." },
    { q: "Why does the RATE of sea level rise matter as much as the total amount?", o: ["A higher rate means the rise will stop sooner", "A faster rate gives coastal communities, ecosystems, and infrastructure less time to adapt", "The rate only affects polar ecosystems far from human populations", "A slower rate means more land ice will melt overall"], a: 1, exp: "The rate of sea level rise matters because faster rise gives less time for coastal communities to adapt, for ecosystems to adjust, and for infrastructure to be redesigned or relocated." },
    { q: "What does 'reduce' mean as the top priority in the waste hierarchy?", o: ["Reducing the number of products that are recycled each year", "Using fewer resources and producing less waste in the first place", "Reducing the physical size of landfill sites", "Reducing the energy used only in the manufacturing stage"], a: 1, exp: "Reduce means consuming fewer resources and generating less waste from the outset — for example, buying products with less packaging or choosing durable, long-lasting items over disposables." },
    { q: "What evidence do ice cores provide about pre-industrial CO₂ levels?", o: ["Ice cores contain ancient plant material that can be directly carbon-dated", "Air bubbles trapped as snow compressed to ice preserve ancient atmospheric samples, allowing CO₂ levels to be measured back 800 000 years", "Ice cores contain fossilised greenhouse gases from extinct organisms", "Ice cores show temperature changes but cannot measure CO₂ levels"], a: 1, exp: "Ice cores from Antarctica and Greenland trap air bubbles as snow compresses; scientists extract and analyse these ancient air samples to reconstruct atmospheric CO₂ concentrations over up to 800 000 years." },
    { q: "What does 'intergenerational harm' mean in the context of environmental pollution?", o: ["Harm caused only to children currently alive today", "Persistent pollutants accumulate in the environment and food chains, exposing future generations to risks from pollution created by previous generations", "Older generations blaming younger generations for causing environmental damage", "Pollution that automatically worsens with each new generation of exposure"], a: 1, exp: "Intergenerational harm refers to persistent pollutants (lead, microplastics, PCBs) that remain in soil, water, and food chains for decades or centuries, exposing future generations to risks from pollution caused by earlier generations." },
    { q: "Why is the 'wet gets wetter, dry gets drier' pattern particularly concerning for southern Australia?", o: ["Southern Australia is already very wet and flooding is the main risk", "Southern Australia falls in the mid-latitude subtropical dry zone experiencing drying trends, threatening water supply and agriculture", "Southern Australia relies entirely on desalination and is not affected by changes in rainfall", "Climate models predict southern Australia will become tropical in climate"], a: 1, exp: "Southern Australia (including the Murray-Darling Basin) falls in a mid-latitude subtropical region predicted to dry further under climate change, threatening water security, agriculture, and river ecosystems." },
    { q: "How does cultural burning demonstrate sustainability principles?", o: ["It maximises the harvest of native food plants in one season", "It maintains biodiversity through habitat mosaics and reduces catastrophic wildfire risk — demonstrating intergenerational care for Country", "It eliminates all insects and pests permanently from the landscape", "It is a complete replacement for naturally occurring wildfires"], a: 1, exp: "Cultural burning demonstrates intergenerational equity (knowledge protecting Country for future generations) and biodiversity conservation by creating habitat mosaics at a landscape scale that benefit many species." },
    { q: "Which is the best example of applying the precautionary principle?", o: ["Waiting until a new chemical causes measurable ecosystem harm before restricting its use", "Restricting a new pesticide until its effects on native bees and aquatic life are fully understood", "Using all available resources as quickly as possible before they run out", "Only acting on environmental issues once 100% scientific certainty exists"], a: 1, exp: "The precautionary principle requires protective action when potential harm exists, even without complete certainty; restricting a new chemical pending safety research is a clear application of this principle." },
    { q: "How does Arctic sea ice loss contribute to further warming through a positive feedback loop?", o: ["Less ice means less water vapour evaporates from the Arctic Ocean", "White ice reflects sunlight; when it melts, darker ocean water absorbs more solar radiation, accelerating warming and melting more ice", "Melting sea ice releases stored methane directly into the atmosphere in large quantities", "Sea ice controls global wind patterns that normally cool the tropics"], a: 1, exp: "Sea ice is highly reflective (high albedo); when it melts, it exposes darker ocean water that absorbs far more solar radiation, warming the ocean and melting more ice — a positive (amplifying) feedback loop." },
    { q: "The Great Barrier Reef has experienced mass bleaching in 1998, 2002, 2016, 2017, 2020, and 2022. What trend does this show?", o: ["Coral bleaching is becoming less frequent as corals adapt", "Mass bleaching events are becoming more frequent, consistent with rising ocean temperatures driven by the enhanced greenhouse effect", "Bleaching is caused by industrial pollution rather than temperature change", "The reef fully recovers between each bleaching event without long-term harm"], a: 1, exp: "The increasing frequency of mass bleaching events on the Great Barrier Reef is consistent with the trend of rising ocean temperatures driven by the enhanced greenhouse effect." },
    { q: "What does the Landsat satellite mission track, and why is it useful for climate science?", o: ["Ocean temperature and sea level height", "Forest and land cover change using optical imaging, with data going back to 1972", "Atmospheric CO₂ concentrations globally", "Ice sheet thickness and mass changes"], a: 1, exp: "Landsat satellites (NASA/USGS) capture optical images of Earth's surface and have tracked forest cover, land use change, and deforestation globally since 1972 — providing a decades-long record for climate change research." },
    { q: "Which of the following is the best definition of a 'renewable' energy source?", o: ["An energy source that produces no greenhouse gases at all", "An energy source that is naturally replenished on human timescales and will not run out as long as the natural process driving it continues", "An energy source that costs very little to operate", "An energy source that can be stored in a battery for later use"], a: 1, exp: "Renewable energy sources (such as solar, wind, hydro) are naturally replenished on human timescales by ongoing natural processes; they will not run out as long as those processes (sunlight, wind, water cycle) continue." },
    { q: "What is the key difference between the natural greenhouse effect and the enhanced greenhouse effect?", o: ["The natural greenhouse effect does not involve CO₂; the enhanced one does", "The natural greenhouse effect maintains habitable temperatures; the enhanced effect results from elevated greenhouse gas concentrations due to human activity, causing extra warming", "The enhanced greenhouse effect is caused by ozone depletion, not CO₂", "The natural greenhouse effect causes cooling; the enhanced effect causes warming"], a: 1, exp: "The natural greenhouse effect is an essential process maintaining Earth at +15°C; the enhanced effect is caused by human activities increasing greenhouse gas concentrations beyond natural levels, intensifying warming." },
    { q: "What is one consequence of climate change for freshwater availability in regions supplied by glacier meltwater?", o: ["Glaciers melting increases river flow permanently", "As glaciers shrink, dry-season river flows decrease over time, reducing freshwater availability", "Glacier melt only affects sea level, not river flow", "Smaller glaciers produce cooler, cleaner water for downstream communities"], a: 1, exp: "Mountain glaciers act as natural water storage, releasing meltwater into rivers in dry seasons; as they shrink due to rising temperatures, dry-season flows decline, threatening water supply for hundreds of millions of people." },
    { q: "What does 'biodiversity conservation' mean in the context of sustainability?", o: ["Growing as many crop species as possible for food security", "Maintaining species diversity to preserve ecosystem resilience and the services ecosystems provide", "Protecting only endangered mammals and birds from extinction", "Ensuring genetic diversity within a single species only"], a: 1, exp: "Biodiversity conservation means maintaining the variety of species and ecosystems; diverse ecosystems are more resilient to disturbance and continue to provide services (clean water, pollination, food) that underpin human well-being." },
    { q: "Why do scientists use multiple independent datasets (NASA, NOAA, UK Met Office) to confirm global temperature trends?", o: ["Each organisation measures temperature in a different country only", "Using multiple independent datasets reduces the chance that the trend is an artefact of one organisation's methods or errors, strengthening confidence in the finding", "Government organisations are always more accurate than independent scientists", "Averaging more datasets always produces higher temperature readings"], a: 1, exp: "When multiple independent organisations using different instruments, methods, and data sources all show the same warming trend, it greatly strengthens confidence that the trend is real and not an artefact of any single dataset." }
  ]
};
